//! Routing and navigation templates for generated webapp code

use crate::webgen::ast::entity::EntityDefinition;
use crate::webgen::parser::{to_pascal_case, to_snake_case, to_kebab_case, pluralize};

/// Routing component templates
pub struct RoutingTemplates;

impl RoutingTemplates {
    /// Generate route definitions for entities
    pub fn generate_route_definitions(entities: &[EntityDefinition], module_name: &str) -> String {
        let mut routes = String::new();

        routes.push_str(r#"/**
 * Auto-generated route definitions for "#);
        routes.push_str(module_name);
        routes.push_str(r#"
 *
 * This file contains route paths and constants for all entities.
 * Generated by metaphor-webgen
 */

export const ROUTE_PATHS = {
"#);

        for entity in entities {
            let entity_snake = to_snake_case(&entity.name);
            let entity_kebab = to_kebab_case(&entity.name);
            let entity_kebab_plural = pluralize(&entity_kebab);
            let entity_pascal = to_pascal_case(&entity.name);
            let has_soft_delete = entity.has_soft_delete();

            routes.push_str("  // ");
            routes.push_str(&entity_pascal);
            routes.push_str(" routes\n");
            routes.push_str("  ");
            routes.push_str(&entity_snake);
            routes.push_str(r#": {
    list: '/"#);
            routes.push_str(&entity_kebab_plural);
            routes.push_str(r#"',
    detail: '/"#);
            routes.push_str(&entity_kebab_plural);
            routes.push_str(r#"/:id',
    create: '/"#);
            routes.push_str(&entity_kebab_plural);
            routes.push_str(r#"/create',
    edit: '/"#);
            routes.push_str(&entity_kebab_plural);
            routes.push_str(r#"/:id/edit',"#);

            // Add trash routes if entity has soft delete
            if has_soft_delete {
                routes.push_str(r#"
    trash: '/"#);
                routes.push_str(&entity_kebab_plural);
                routes.push_str(r#"/trash',
    trashDetail: '/"#);
                routes.push_str(&entity_kebab_plural);
                routes.push_str(r#"/trash/:id',"#);
            }

            routes.push_str("\n  },");
            routes.push('\n');
        }

        routes.push_str(r#"} as const;

export type RoutePath = typeof ROUTE_PATHS;

/**
 * Get route path with parameters
 */
export function getRoutePath(
  entity: keyof RoutePath,
  type: 'list' | 'detail' | 'create' | 'edit' | 'trash' | 'trashDetail',
  params?: { id?: string }
): string {
  const entityRoutes = ROUTE_PATHS[entity];
  const basePath = entityRoutes[type as keyof typeof entityRoutes];

  if (!basePath) {
    console.warn(`Route type '${type}' not found for entity '${String(entity)}'`);
    return '/';
  }

  if (!params) {
    return basePath;
  }

  return basePath.replace(':id', params.id ?? '');
}

// <<< CUSTOM: Add custom route definitions here
// END CUSTOM
"#);
        routes
    }

    /// Generate route component map
    pub fn generate_route_components(entities: &[EntityDefinition], module_name: &str) -> String {
        let mut routes = String::new();

        routes.push_str(r#"import { lazy } from 'react';

/**
 * Auto-generated route components for "#);
        routes.push_str(module_name);
        routes.push_str(r#"
 *
 * This file contains lazy-loaded component imports for all entities.
 * NOTE: TypeScript cannot resolve .tsx extensions in dynamic imports with moduleResolution: "bundler".
 * Vite handles these correctly at runtime, so we suppress the errors.
 * Generated by metaphor-webgen
 */

"#);

        for entity in entities {
            let entity_pascal = to_pascal_case(&entity.name);
            let entity_snake = to_snake_case(&entity.name);
            let entity_snake_plural = pluralize(&entity_snake);
            let has_soft_delete = entity.has_soft_delete();

            routes.push_str("// ");
            routes.push_str(&entity_pascal);
            routes.push_str(" components\n");

            // List page - uses barrel export from entity pages directory
            routes.push_str("function load");
            routes.push_str(&entity_pascal);
            routes.push_str("ListPage() {\n  // @ts-expect-error - Vite handles .tsx dynamic imports\n  return import('@webapp/presentation/pages/");
            routes.push_str(module_name);
            routes.push('/');
            routes.push_str(&entity_snake_plural);
            routes.push_str("').then(m => ({ default: m.");
            routes.push_str(&entity_pascal);
            routes.push_str("ListPage }));\n}\n\nexport const ");

            routes.push_str(&entity_pascal);
            routes.push_str("ListComponent = lazy(() => load");
            routes.push_str(&entity_pascal);
            routes.push_str("ListPage());\n\n");

            // Detail page
            routes.push_str("function load");
            routes.push_str(&entity_pascal);
            routes.push_str("DetailPage() {\n  // @ts-expect-error\n  return import('@webapp/presentation/pages/");
            routes.push_str(module_name);
            routes.push('/');
            routes.push_str(&entity_snake_plural);
            routes.push_str("').then(m => ({ default: m.");
            routes.push_str(&entity_pascal);
            routes.push_str("DetailPage }));\n}\n\nexport const ");

            routes.push_str(&entity_pascal);
            routes.push_str("DetailComponent = lazy(() => load");
            routes.push_str(&entity_pascal);
            routes.push_str("DetailPage());\n\n");

            // Create page
            routes.push_str("function load");
            routes.push_str(&entity_pascal);
            routes.push_str("CreatePage() {\n  // @ts-expect-error\n  return import('@webapp/presentation/pages/");
            routes.push_str(module_name);
            routes.push('/');
            routes.push_str(&entity_snake_plural);
            routes.push_str("').then(m => ({ default: m.");
            routes.push_str(&entity_pascal);
            routes.push_str("CreatePage }));\n}\n\nexport const ");

            routes.push_str(&entity_pascal);
            routes.push_str("CreateComponent = lazy(() => load");
            routes.push_str(&entity_pascal);
            routes.push_str("CreatePage());\n\n");

            // Edit page
            routes.push_str("function load");
            routes.push_str(&entity_pascal);
            routes.push_str("EditPage() {\n  // @ts-expect-error\n  return import('@webapp/presentation/pages/");
            routes.push_str(module_name);
            routes.push('/');
            routes.push_str(&entity_snake_plural);
            routes.push_str("').then(m => ({ default: m.");
            routes.push_str(&entity_pascal);
            routes.push_str("EditPage }));\n}\n\nexport const ");

            routes.push_str(&entity_pascal);
            routes.push_str("EditComponent = lazy(() => load");
            routes.push_str(&entity_pascal);
            routes.push_str("EditPage());\n\n");

            // Trash pages (if soft delete is enabled)
            if has_soft_delete {
                // Trash list page
                routes.push_str("function load");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashPage() {\n  // @ts-expect-error\n  return import('@webapp/presentation/pages/");
                routes.push_str(module_name);
                routes.push('/');
                routes.push_str(&entity_snake_plural);
                routes.push_str("').then(m => ({ default: m.");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashPage }));\n}\n\nexport const ");

                routes.push_str(&entity_pascal);
                routes.push_str("TrashComponent = lazy(() => load");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashPage());\n\n");

                // Trash detail page
                routes.push_str("function load");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashDetailPage() {\n  // @ts-expect-error\n  return import('@webapp/presentation/pages/");
                routes.push_str(module_name);
                routes.push('/');
                routes.push_str(&entity_snake_plural);
                routes.push_str("').then(m => ({ default: m.");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashDetailPage }));\n}\n\nexport const ");

                routes.push_str(&entity_pascal);
                routes.push_str("TrashDetailComponent = lazy(() => load");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashDetailPage());\n\n");
            }
        }

        routes.push_str(r#"
// <<< CUSTOM: Add custom component imports here
// END CUSTOM
"#);
        routes
    }

    /// Generate route configuration
    pub fn generate_route_config(entities: &[EntityDefinition], module_name: &str) -> String {
        let mut routes = String::new();

        routes.push_str(r#"import { RouteObject } from 'react-router-dom';
import { ROUTE_PATHS } from './routes';
import {
"#);

        for entity in entities {
            let entity_pascal = to_pascal_case(&entity.name);
            let has_soft_delete = entity.has_soft_delete();

            routes.push_str("  ");
            routes.push_str(&entity_pascal);
            routes.push_str("ListComponent,\n  ");
            routes.push_str(&entity_pascal);
            routes.push_str("DetailComponent,\n  ");
            routes.push_str(&entity_pascal);
            routes.push_str("CreateComponent,\n  ");
            routes.push_str(&entity_pascal);
            routes.push_str("EditComponent,\n");

            if has_soft_delete {
                routes.push_str("  ");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashComponent,\n  ");
                routes.push_str(&entity_pascal);
                routes.push_str("TrashDetailComponent,\n");
            }
        }

        // Remove trailing comma
        if routes.ends_with(",\n") {
            routes.pop();
            routes.pop();
        }

        routes.push_str(r#"} from './route-components';

/**
 * Auto-generated route configuration for "#);
        routes.push_str(module_name);
        routes.push_str(r#"
 *
 * This file contains the route configuration array for React Router.
 * Add these routes to your AppRouter.
 * Generated by metaphor-webgen
 */

export const "#);
        routes.push_str(module_name);
        routes.push_str("Routes: RouteObject[] = [\n");

        for entity in entities {
            let entity_pascal = to_pascal_case(&entity.name);
            let entity_snake = to_snake_case(&entity.name);
            let has_soft_delete = entity.has_soft_delete();

            routes.push_str(r#"  {
    path: ROUTE_PATHS."#);
            routes.push_str(&entity_snake);
            routes.push_str(r#".list,
    element: <"#);
            routes.push_str(&entity_pascal);
            routes.push_str(r#"ListComponent />,
  },
  {
    path: ROUTE_PATHS."#);
            routes.push_str(&entity_snake);
            routes.push_str(r#".create,
    element: <"#);
            routes.push_str(&entity_pascal);
            routes.push_str(r#"CreateComponent />,
  },
  {
    path: ROUTE_PATHS."#);
            routes.push_str(&entity_snake);
            routes.push_str(r#".detail,
    element: <"#);
            routes.push_str(&entity_pascal);
            routes.push_str(r#"DetailComponent />,
  },
  {
    path: ROUTE_PATHS."#);
            routes.push_str(&entity_snake);
            routes.push_str(r#".edit,
    element: <"#);
            routes.push_str(&entity_pascal);
            routes.push_str(r#"EditComponent />,
  },
"#);

            // Add trash routes if entity has soft delete
            if has_soft_delete {
                routes.push_str(r#"  {
    path: ROUTE_PATHS."#);
                routes.push_str(&entity_snake);
                routes.push_str(r#".trash,
    element: <"#);
                routes.push_str(&entity_pascal);
                routes.push_str(r#"TrashComponent />,
  },
  {
    path: ROUTE_PATHS."#);
                routes.push_str(&entity_snake);
                routes.push_str(r#".trashDetail,
    element: <"#);
                routes.push_str(&entity_pascal);
                routes.push_str(r#"TrashDetailComponent />,
  },
"#);
            }
        }

        routes.push_str(r#"];

// <<< CUSTOM: Add custom routes here
// END CUSTOM
"#);
        routes
    }

    /// Generate navigation menu
    pub fn generate_navigation_menu(entities: &[EntityDefinition], module_name: &str) -> String {
        let mut nav = String::new();

        nav.push_str(r#"import { ListItem, ListItemDecorator, ListItemContent } from '@/components/ui';
import { Link } from 'react-router-dom';
import {
"#);

        // Generate icon imports (placeholder - user should replace)
        for entity in entities {
            let entity_pascal = to_pascal_case(&entity.name);
            nav.push_str("  ");
            nav.push_str(&entity_pascal);
            nav.push_str("Icon as ");
            nav.push_str(&entity_pascal);
            nav.push_str("IconSvg,\n");
        }

        // Remove trailing comma
        if nav.ends_with(",\n") {
            nav.pop();
            nav.pop();
        }

        nav.push_str(r#"} from '@/shared/icons';

/**
 * Auto-generated navigation menu for "#);
        nav.push_str(module_name);
        nav.push_str(r#"
 *
 * This file contains navigation menu items for all entities.
 * Generated by metaphor-webgen
 */

export interface NavItem {
  path: string;
  label: string;
  icon: React.ComponentType<{ className?: string }>;
  children?: NavItem[];
}

export const "#);
        nav.push_str(module_name);
        nav.push_str("NavItems: NavItem[] = [\n");

        for entity in entities {
            let entity_pascal = to_pascal_case(&entity.name);
            let entity_kebab = to_kebab_case(&entity.name);
            let entity_kebab_plural = pluralize(&entity_kebab);

            nav.push_str("  {\n");
            nav.push_str("    path: '/");
            nav.push_str(module_name);
            nav.push('/');
            nav.push_str(&entity_kebab_plural);
            nav.push_str(r#"',
    label: '"#);
            nav.push_str(&entity_pascal);
            nav.push_str(r#"',
    icon: "#);
            nav.push_str(&entity_pascal);
            nav.push_str("IconSvg,\n");
            nav.push_str("  },\n");
        }

        nav.push_str(r#"];

/**
 * Generate navigation menu items from config
 */
export function generateNavMenuItems(items: NavItem[]) {
  return items.map((item) => (
    <ListItem
      key={item.path}
      component={Link}
      to={item.path}
    >
      {item.icon && <ListItemDecorator>{<item.icon />}</ListItemDecorator>}
      <ListItemContent>{item.label}</ListItemContent>
    </ListItem>
  ));
}

// <<< CUSTOM: Add custom navigation items here
// END CUSTOM
"#);
        nav
    }
}

